import { test, expect } from '@playwright/test';

test('Navigate to Profile tab on Yahoo Finance MSFT page', async ({ page }) => {
  // Navigate to the MSFT Yahoo Finance page
  await page.goto('https://sg.finance.yahoo.com/quote/MSFT/');

  // Wait for the navigation tabs to be visible
  const profileTab = page.locator('a[role="menuitem"]').filter({ hasText: 'Profile' });
  await expect(profileTab).toBeVisible({ timeout: 10000 });

  // Click the Profile tab
  await profileTab.click();

  // Wait for the page to stabilize by waiting for a unique element in the Profile section
  // For example, the heading "Profile" or company description
  await expect(page.getByText('Profile', { exact: true })).toBeVisible({ timeout: 10000 });

  // Optionally, verify that the URL contains "/profile"
  await expect(page).toHaveURL(/\/profile/);
});
